package escalation

import (
	"encoding/json"
	"fmt"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// SuccessStatus mirrors agent.ExecuteBeadStatusSuccess. The agent package's
// TestEscalatableStatusesMatchAgentVocab guard catches drift if either side
// renames. Defined locally so escalation does not import agent.
const SuccessStatus = "success"

// EscalatableStatuses is the set of executor status strings that warrant
// retrying with a higher powerClass. Mirrors a subset of agent.ExecuteBeadStatus*
// strings; the agent package has a TestEscalatableStatusesMatchAgentVocab
// guard (see agent/tier_escalation_alignment_test.go) to catch drift.
var EscalatableStatuses = map[string]bool{
	"execution_failed":       true,
	"post_run_check_failed":  true,
	"land_conflict":          true,
	"review_request_changes": true,
	"review_block":           true,
}

// ShouldEscalate reports whether status warrants escalating to the next powerClass.
// Structural failures (e.g. validation errors) do not escalate because a
// smarter model cannot fix a malformed prompt or corrupted bead state.
func ShouldEscalate(status string) bool {
	return EscalatableStatuses[status]
}

// ProviderCooldownDuration is how long an unhealthy harness is skipped before
// re-probing. Five minutes gives most transient errors time to resolve without
// locking out a provider for too long.
//
// Per-harness cooldown tracking moved to the upstream agent service in v0.8.0:
// callers record failures via svc.RecordRouteAttempt and read cooldown state
// via svc.RouteStatus's RouteCandidateStatus.Healthy (ddx-7bc0c8d5).
const ProviderCooldownDuration = 5 * time.Minute

// FormatPowerAttemptBody formats the body of a power-attempt bead event.
func FormatPowerAttemptBody(powerClass, harness, model, probeResult, detail string) string {
	body := fmt.Sprintf("powerClass=%s harness=%s model=%s", powerClass, harness, model)
	if probeResult != "" {
		body += " probe=" + probeResult
	}
	if detail != "" {
		body += "\n" + detail
	}
	return body
}

// EscalationWinningExhausted is the sentinel value written into the
// winning_power_class field of an escalation-summary body when the escalation loop
// ran through every eligible powerClass without producing a successful attempt.
const EscalationWinningExhausted = "exhausted"

// PowerAttemptRecord is one row of an escalation trace. It captures the
// powerClass/harness/model that was tried, the status that attempt returned, and
// the cost/duration the harness reported for that attempt. Skipped powerClasses
// (no viable provider) are recorded with zero cost and zero duration.
type PowerAttemptRecord struct {
	PowerClass string  `json:"power_class"`
	Harness    string  `json:"harness,omitempty"`
	Model      string  `json:"model,omitempty"`
	Status     string  `json:"status"`
	CostUSD    float64 `json:"cost_usd"`
	DurationMS int64   `json:"duration_ms"`
}

// EscalationSummary is the structured body of a kind:escalation-summary bead
// event. It captures the entire escalation trace so an operator can diagnose
// which powerClasses were tried, which one won (if any), and how much the path cost.
type EscalationSummary struct {
	PowerAttempts     []PowerAttemptRecord `json:"power_attempts"`
	WinningPowerClass string               `json:"winning_power_class"`
	TotalCostUSD      float64              `json:"total_cost_usd"`
	WastedCostUSD     float64              `json:"wasted_cost_usd"`
}

// BuildEscalationSummary computes the summary body from the ordered list of
// attempts. winningPowerClass is the string of the powerClass whose attempt succeeded;
// pass "" when the escalation was exhausted, in which case winning_power_class is
// set to EscalationWinningExhausted. Total cost is the sum of all attempt
// costs; wasted cost is the sum of attempts whose status is not
// SuccessStatus.
func BuildEscalationSummary(attempts []PowerAttemptRecord, winningPowerClass string) EscalationSummary {
	out := EscalationSummary{
		PowerAttempts:     append([]PowerAttemptRecord{}, attempts...),
		WinningPowerClass: winningPowerClass,
	}
	if out.WinningPowerClass == "" {
		out.WinningPowerClass = EscalationWinningExhausted
	}
	for _, a := range attempts {
		out.TotalCostUSD += a.CostUSD
		if a.Status != SuccessStatus {
			out.WastedCostUSD += a.CostUSD
		}
	}
	return out
}

// BeadEventAppender records append-only evidence events on a bead. Mirrors
// agent.BeadEventAppender so escalation can append events without importing
// agent. *bead.Store satisfies both interfaces.
type BeadEventAppender interface {
	AppendEvent(id string, event bead.BeadEvent) error
}

// AppendEscalationSummaryEvent writes a kind:escalation-summary event to the
// bead with a JSON body describing the powerClass escalation trace. It is a
// best-effort operation — errors from the underlying store are returned so
// callers can log them, but callers typically ignore the error so telemetry
// failures never abort the main execute-bead flow.
func AppendEscalationSummaryEvent(appender BeadEventAppender, beadID, actor string, attempts []PowerAttemptRecord, winningPowerClass string, createdAt time.Time) error {
	if appender == nil || beadID == "" {
		return nil
	}
	summary := BuildEscalationSummary(attempts, winningPowerClass)
	body, err := json.Marshal(summary)
	if err != nil {
		return err
	}
	return appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "escalation-summary",
		Summary:   fmt.Sprintf("winning_power_class=%s attempts=%d total_cost_usd=%.4f wasted_cost_usd=%.4f", summary.WinningPowerClass, len(attempts), summary.TotalCostUSD, summary.WastedCostUSD),
		Body:      string(body),
		Actor:     actor,
		Source:    "legacy agent work",
		CreatedAt: createdAt,
	})
}

package escalation

import (
	"fmt"
	"strconv"
	"strings"
	"sync"
)

// InfrastructureFailurePatterns are detail substrings that indicate a
// transient infrastructure-level failure (provider 502, network unreachable,
// command not found, auth/quota exhausted) rather than a model-capability
// failure (test failed, build failed, no changes after attempt).
//
// Infrastructure failures should not consume escalation budget — the bead
// should be deferred with a retry-after, not retried at the next powerClass with
// a more expensive model. The model wasn't given a fair chance.
//
// Patterns are matched case-insensitively as substrings of the failure
// detail string. Any new pattern added here is automatically picked up by
// IsInfrastructureFailure callers.
var InfrastructureFailurePatterns = []string{
	// HTTP-level provider unavailability
	"502", "503", "504",
	"bad gateway",
	"service unavailable",
	"gateway timeout",
	// Network-level unreachability
	"connection refused",
	"no such host",
	"no route to host",
	"network is unreachable",
	"i/o timeout",
	"context deadline exceeded",
	// Auth/quota exhaustion (operator-fixable, not a model fault)
	"401", "429",
	"unauthorized",
	"rate limit",
	"ratelimit",
	"quota exceeded",
	"insufficient quota",
	"insufficient_quota",
	// Subprocess harness binary missing or unstartable
	"command not found",
	"executable file not found",
	"no such file or directory",
	// Upstream routing/service selection failures
	"resolveroute:",
	"no viable routing candidate",
	"no live provider supports",
	"no candidate satisfying local endpoint",
}

// IsInfrastructureFailure reports whether the given failure status + detail
// indicates a transient infrastructure problem the model could not have
// fixed. Only execution_failed can be infrastructure; other escalatable
// statuses are semantic outcomes that should proceed through the powerClass ladder.
// Returns false for statuses whose detail does not match any known
// infrastructure pattern.
//
// Used by the work to decide whether to (a) defer the bead with a
// retry-after and try the same powerClass later, or (b) burn through to the next
// powerClass as the standard escalation policy.
func IsInfrastructureFailure(status, detail string) bool {
	if status != "execution_failed" {
		return false
	}
	if detail == "" {
		return false
	}
	lower := strings.ToLower(detail)
	for _, p := range InfrastructureFailurePatterns {
		if strings.Contains(lower, p) {
			return true
		}
	}
	return false
}

// DefaultMaxCostUSD is the per-work dollar cap on accumulated billed
// spend. Exceeding the cap halts further bead claiming so an work
// run cannot silently burn through arbitrary openrouter / pay-per-token
// credits. Local LLMs and subscription-bundled providers do not count
// toward the cap (see CountsTowardCostCap).
//
// $100 is large enough not to interrupt normal subscription-driven work
// (where billed cost stays at $0) and small enough to surface a clear stop
// signal before runaway openrouter usage.
const DefaultMaxCostUSD = 100.0

// DefaultMaxBeadCostUSD is the default per-bead budget. When a single bead
// exhausts this amount across all escalation powerClasses, escalation stops and the
// bead is returned to open without a cooldown. Operators can override
// per-bead with a budget:<USD> label (e.g. budget:25.0).
//
// $5 is a conservative default — enough to attempt two or three smart-powerClass
// runs before halting, but low enough to protect against runaway escalation
// on a pathologically difficult bead.
const DefaultMaxBeadCostUSD = 5.0

// DefaultMaxRecoveryCostUSD is the per-bead recovery budget for automated
// reframe/decompose attempts after repeated ladder exhaustion.
const DefaultMaxRecoveryCostUSD = 2.0

// PerBeadBudgetExhaustedReason is the detail-string prefix written into a
// report when the per-bead budget is exceeded. The work detects this
// marker to handle the outcome correctly (unclaim, event, counter increment,
// no cooldown).
const PerBeadBudgetExhaustedReason = "per-bead budget exhausted"

// CostClassBilled is the HarnessInfo.CostClass value the agent uses for
// pay-per-token providers. Free local providers report "free" and
// subscription-bundled providers report "subscription".
const CostClassBilled = "expensive"

// CountsTowardCostCap returns true when an attempt's reported CostUSD
// should accumulate against the loop's MaxCostUSD. Callers pass the
// HarnessInfo of the harness that ran the attempt; when info is nil the
// safe default is to count (treat unknown as billed).
func CountsTowardCostCap(isLocal, isSubscription bool, costClass string) bool {
	if isLocal {
		return false
	}
	if isSubscription {
		return false
	}
	// CostClass "free" or "subscription" never bill; only "expensive" does.
	if costClass != "" && costClass != CostClassBilled {
		return false
	}
	return true
}

// HarnessBilledLookup reports whether a harness's reported CostUSD should
// be accumulated against a CostCapTracker. Implementations typically
// consult a service.ListHarnesses snapshot. A nil lookup is treated as
// "count by default" (the safe option for unknown harnesses).
type HarnessBilledLookup func(harnessName string) bool

// CostCapTracker accumulates billed cost for a single work run
// and reports when accumulated spend has reached the configured cap.
// Safe for concurrent use across goroutines (workers may call Add and
// Tripped concurrently).
//
// MaxUSD == 0 disables the cap; Tripped always returns (_, false). The
// Lookup callback decides which harnesses contribute to the running
// total — local and subscription-bundled providers should be excluded
// (see CountsTowardCostCap).
type CostCapTracker struct {
	MaxUSD float64
	Lookup HarnessBilledLookup

	mu    sync.Mutex
	spent float64
	// cache memoizes Lookup results so we do not rebuild a service for
	// every reported attempt. Protected by mu.
	cache map[string]bool
}

// NewCostCapTracker constructs a tracker with the given dollar cap and
// lookup. Pass maxUSD <= 0 to disable the cap. A nil lookup is treated
// as "count by default" — every harness contributes.
func NewCostCapTracker(maxUSD float64, lookup HarnessBilledLookup) *CostCapTracker {
	return &CostCapTracker{
		MaxUSD: maxUSD,
		Lookup: lookup,
		cache:  map[string]bool{},
	}
}

// counts reports whether harnessName's CostUSD should accumulate. The
// result is memoized; callers that want fresh resolution should
// construct a new tracker. Lookups for empty harness names default to
// true (count) so accidentally-missing harness metadata never silently
// bypasses the cap.
func (t *CostCapTracker) counts(harnessName string) bool {
	if harnessName == "" {
		return true
	}
	t.mu.Lock()
	if v, ok := t.cache[harnessName]; ok {
		t.mu.Unlock()
		return v
	}
	t.mu.Unlock()
	result := true
	if t.Lookup != nil {
		result = t.Lookup(harnessName)
	}
	t.mu.Lock()
	t.cache[harnessName] = result
	t.mu.Unlock()
	return result
}

// Add accumulates costUSD against the running total when harnessName's
// billing class counts toward the cap. Non-positive cost is ignored.
func (t *CostCapTracker) Add(harnessName string, costUSD float64) {
	if costUSD <= 0 {
		return
	}
	if !t.counts(harnessName) {
		return
	}
	t.mu.Lock()
	t.spent += costUSD
	t.mu.Unlock()
}

// Spent returns the current accumulated billed total.
func (t *CostCapTracker) Spent() float64 {
	t.mu.Lock()
	defer t.mu.Unlock()
	return t.spent
}

// Tripped reports whether the accumulated spend has reached MaxUSD. When
// MaxUSD <= 0 the cap is disabled and Tripped returns (_, false).
// Returns the formatted operator-facing detail string when tripped so
// callers can populate a stop-the-loop ExecuteBeadReport.

package agent

import (
	"context"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestZeroConfigRetryEscalationPolicy verifies the retry/escalation policy
// composes correctly when the loop starts from the default standard powerClass.
// Transient failures retry within the same powerClass and substantive failures
// escalate standard -> smart.
//
// The test drives a simulated powerClass ladder using the real escalation
// primitives (InferPowerClass, IsInfrastructureFailure, ShouldEscalate,
// BuildEscalationSummary). It does not require a running
// agent service or harness binary.
func TestZeroConfigRetryEscalationPolicy(t *testing.T) {
	// 1. Unflagged bead: no explicit estimated-difficulty hint.
	// InferPowerClass must default to standard; cheap and smart require the
	// single explicit bead metadata hint or later retry escalation.
	b := &bead.Bead{
		ID:          "ddx-zero-config-001",
		Title:       "trivial cleanup, unflagged",
		Description: "minor doc tweak",
	}
	startPowerClass := escalation.InferPowerClass(b)
	require.Equal(t, escalation.PowerStandard, startPowerClass,
		"unflagged bead must infer standard powerClass")
	require.Equal(t, "standard", string(startPowerClass),
		"standard powerClass maps to the ordinary implementation profile")

	// 2. Transient infrastructure failure on standard powerClass (e.g. 502 from
	// the inference host). The policy is: do NOT escalate; defer with a
	// retry-after and try the same powerClass again. The model wasn't given
	// a fair chance, so escalation budget must not be consumed.
	transientStatus := ExecuteBeadStatusExecutionFailed
	transientDetail := "provider 502 Bad Gateway: connection refused"
	require.True(t,
		escalation.IsInfrastructureFailure(transientStatus, transientDetail),
		"502 Bad Gateway on execution_failed must be classified as infrastructure failure")
	require.True(t,
		escalation.ShouldEscalate(transientStatus),
		"execution_failed itself remains escalatable; the loop must consult IsInfrastructureFailure first to defer-vs-escalate")

	// Loop ordering invariant: when IsInfrastructureFailure is true the
	// loop body defers (retry-after) instead of advancing the powerClass. The
	// powerClass on the next attempt is therefore unchanged.
	powerClassAfterTransient := startPowerClass
	require.Equal(t, escalation.PowerStandard, powerClassAfterTransient,
		"transient failure must not advance the powerClass ladder")

	// 3. Substantive failure on standard powerClass (e.g. tests failed). Policy:
	// escalate to the next powerClass (smart).
	substantiveStatus := ExecuteBeadStatusExecutionFailed
	substantiveDetail := "TestFoo failed: assertion mismatch"
	require.False(t,
		escalation.IsInfrastructureFailure(substantiveStatus, substantiveDetail),
		"a model-capability failure detail must not match infrastructure patterns")
	require.True(t,
		escalation.ShouldEscalate(substantiveStatus),
		"substantive execution_failed must escalate")
	powerClassAfterStandardSubstantive := nextPowerClass(powerClassAfterTransient)
	require.Equal(t, escalation.PowerSmart, powerClassAfterStandardSubstantive,
		"standard -> smart escalation step")

	// 4. Smart powerClass succeeds. Build the escalation summary and verify
	// the full trail is recorded with winning_power_class=smart and the
	// transient attempt counted as deferred but not escalated.
	attempts := []escalation.PowerAttemptRecord{
		{PowerClass: string(escalation.PowerStandard), Harness: "codex", Model: "standard-model", Status: transientStatus, CostUSD: 0.0, DurationMS: 800},
		{PowerClass: string(escalation.PowerStandard), Harness: "codex", Model: "standard-model", Status: substantiveStatus, CostUSD: 0.15, DurationMS: 3400},
		{PowerClass: string(escalation.PowerSmart), Harness: "claude", Model: "smart-model", Status: escalation.SuccessStatus, CostUSD: 0.80, DurationMS: 9000},
	}
	summary := escalation.BuildEscalationSummary(attempts, string(escalation.PowerSmart))
	require.Equal(t, string(escalation.PowerSmart), summary.WinningPowerClass,
		"smart powerClass won the escalation")
	require.Len(t, summary.PowerAttempts, 3,
		"trail records all attempts including the deferred-transient standard attempt")
	assert.InDelta(t, 0.95, summary.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.15, summary.WastedCostUSD, 1e-9,
		"standard-substantive wasted; standard-transient billed $0; smart succeeded")
	assert.Equal(t, string(escalation.PowerStandard), summary.PowerAttempts[0].PowerClass,
		"first attempt was standard")
	assert.Equal(t, string(escalation.PowerSmart), summary.PowerAttempts[2].PowerClass,
		"final attempt was smart (top of ladder)")
}

// TestZeroConfigEscalationSummaryEventBody verifies the escalation summary
// is emitted as a kind:escalation-summary bead event when the standard-default
// ladder runs to completion. This is the operator-visible artifact of the
// retry/escalation policy.
func TestZeroConfigEscalationSummaryEventBody(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))
	target := &bead.Bead{ID: "ddx-zero-config-002", Title: "standard-default ladder", Priority: 0}
	require.NoError(t, store.Create(context.Background(), target))

	attempts := []escalation.PowerAttemptRecord{
		{PowerClass: string(escalation.PowerStandard), Status: ExecuteBeadStatusExecutionFailed, CostUSD: 0.10, DurationMS: 2000},
		{PowerClass: string(escalation.PowerSmart), Status: escalation.SuccessStatus, CostUSD: 0.50, DurationMS: 4000},
	}
	require.NoError(t,
		escalation.AppendEscalationSummaryEvent(
			store, target.ID, "test-worker", attempts, string(escalation.PowerSmart), time.Unix(1, 0).UTC()))

	events, err := store.Events(target.ID)
	require.NoError(t, err)
	var found *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "escalation-summary" {
			found = &events[i]
			break
		}
	}
	require.NotNil(t, found, "escalation-summary event must be appended for the standard-default ladder run")
	assert.Contains(t, found.Summary, "winning_power_class=smart")
	assert.Contains(t, found.Summary, "attempts=2")
	assert.Contains(t, found.Body, `"power_class":"standard"`)
	assert.Contains(t, found.Body, `"power_class":"smart"`)
}

// nextPowerClass advances one rung up the cheap -> standard -> smart ladder.
// Mirrors the implicit ladder used by the work when escalating
// beyond a substantive failure. Smart is the top; further calls stay
// at smart (callers exhaust escalation when ShouldEscalate fires at smart).
func nextPowerClass(t escalation.PowerClass) escalation.PowerClass {
	switch t {
	case escalation.PowerCheap:
		return escalation.PowerStandard
	case escalation.PowerStandard:
		return escalation.PowerSmart
	default:
		return escalation.PowerSmart
	}
}

